INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_military_presence','Arctic military build-up and NATO expansion','Militärischer Aufbau in der Arktis und NATO-Erweiterung','The re-militarization of the High North: Russia''s rebuilt bases and Northern Fleet along the Kola Peninsula and Barents Sea, and NATO''s answer — enlarged by Finnish and Swedish accession — through exercises, reinforcement and new basing, increasingly shadowed by Sino-Russian cooperation. The contest is over who is the provocateur. Western and Nordic coverage frames the build-up as necessary deterrence; Russian and Chinese state media cast NATO expansion as the destabilizing militarization of a once-low-tension zone.','Die erneute Militarisierung des hohen Nordens: Russlands wiederaufgebaute Stützpunkte und Nordflotte entlang der Kola-Halbinsel und der Barentssee sowie die Antwort der durch den finnischen und schwedischen Beitritt vergrößerten NATO durch Übungen, Verstärkung und neue Stützpunkte, zunehmend begleitet von russisch-chinesischer Kooperation. Umstritten ist, wer der Provokateur ist. Westliche und nordische Berichterstattung sieht den Aufbau als notwendige Abschreckung; russische und chinesische Staatsmedien stellen die NATO-Erweiterung als destabilisierende Militarisierung einer einst spannungsarmen Zone dar.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-NORDIC','AMERICAS-CANADA','NON-STATE-NATO','NON-STATE-EU','ASIA-CHINA'],true,110,'The High North is re-militarizing. Russia has rebuilt Cold-War-era bases and its Northern Fleet along the Kola Peninsula and Barents Sea; NATO, enlarged by Finnish and Swedish accession, has answered with exercises such as Arctic Sentry, Cold Response and Nordic Response, reinforcement of its northern flank and new basing, increasingly shadowed by Sino-Russian cooperation. The contest is over who is the provocateur: Western and Nordic coverage frames the build-up as necessary deterrence against a growing Russian and Chinese threat, while Russian and Chinese state media reverse the causality, casting NATO expansion as the destabilizing militarization of a once-low-tension zone and an encirclement of Russia.','Der hohe Norden militarisiert sich erneut. Russland hat Stützpunkte aus dem Kalten Krieg und seine Nordflotte entlang der Kola-Halbinsel und der Barentssee wiederaufgebaut; die durch den finnischen und schwedischen Beitritt vergrößerte NATO hat mit Übungen wie Arctic Sentry, Cold Response und Nordic Response, der Verstärkung ihrer Nordflanke und neuen Stützpunkten geantwortet, zunehmend begleitet von russisch-chinesischer Kooperation. Umstritten ist, wer der Provokateur ist: westliche und nordische Berichterstattung sieht den Aufbau als notwendige Abschreckung gegen eine wachsende russische und chinesische Bedrohung, während russische und chinesische Staatsmedien die Kausalität umkehren und die NATO-Erweiterung als destabilisierende Militarisierung einer einst spannungsarmen Zone und Einkreisung Russlands darstellen.','atomic',NULL,'{}','regional',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_resources_competition','Arctic resources competition and climate access','Wettbewerb um arktische Rohstoffe und Klimazugang','The race for Arctic hydrocarbons and critical minerals as retreating ice opens access — Russia''s Yamal gas and Vostok oil, Norway''s Barents fields, Alaska''s Willow project, Greenland''s rare earths — contested by Arctic states and China. It sets a development camp that treats extraction as a legitimate sovereign right against its own critics, who warn that the same warming which opens the region — record-low sea ice, thawing permafrost, black carbon — is a climate emergency that drilling and mining only deepen.','Das Rennen um arktische Kohlenwasserstoffe und kritische Rohstoffe, während das zurückweichende Eis den Zugang öffnet — Russlands Jamal-Gas und Wostok-Öl, Norwegens Barents-Felder, Alaskas Willow-Projekt, Grönlands Seltene Erden — umkämpft von Arktis-Staaten und China. Es stellt ein Entwicklungslager, das die Förderung als legitimes souveränes Recht betrachtet, gegen dessen eigene Kritiker, die warnen, dass dieselbe Erwärmung, die die Region öffnet — Rekordtief beim Meereis, tauender Permafrost, Ruß — ein Klimanotstand ist, den Bohrungen und Bergbau nur vertiefen.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-GREENLAND','AMERICAS-CANADA','ASIA-CHINA','NON-STATE-EU','EUROPE-NORDIC'],true,111,'As the ice retreats it exposes an estimated fortune in Arctic hydrocarbons and critical minerals — Russia''s Yamal gas and Vostok oil, Norway''s Barents fields, Alaska''s Willow project, Greenland''s rare earths — turning the region into a resource frontier contested by Arctic states and China alike. Two stances frame it: a development camp of Russian state and Western energy press that treats extraction as a legitimate, economically vital sovereign right, and its own critics, who warn that the same warming that opens access — record-low sea ice, thawing permafrost, black carbon — is a climate emergency that drilling, mining and shipping only compound. Because the outlets reporting the resource boom often sound the environmental alarm too, the split is one of framing rather than of camp.','Mit dem Rückzug des Eises tritt ein geschätztes Vermögen an arktischen Kohlenwasserstoffen und kritischen Rohstoffen zutage — Russlands Jamal-Gas und Wostok-Öl, Norwegens Barents-Felder, Alaskas Willow-Projekt, Grönlands Seltene Erden — und macht die Region zu einer Rohstoff-Grenze, um die Arktis-Staaten und China gleichermaßen konkurrieren. Zwei Haltungen rahmen dies: ein Entwicklungslager aus russischer Staats- und westlicher Energiepresse, das die Förderung als legitimes, wirtschaftlich wichtiges souveränes Recht betrachtet, und dessen eigene Kritiker, die warnen, dass dieselbe Erwärmung, die den Zugang öffnet — Rekordtief beim Meereis, tauender Permafrost, Ruß — ein Klimanotstand ist, den Bohrungen, Bergbau und Schifffahrt nur verschärfen. Da dieselben Medien Boom und Umweltalarm berichten, ist die Trennung eine der Rahmung, nicht des Lagers.','atomic',NULL,'{}','regional',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_shipping_routes','Arctic shipping routes and passage competition','Arktische Schifffahrtsrouten und Passagenwettbewerb','The competition over the sea routes that Arctic warming is opening — the Northern Sea Route along Russia''s coast, the Northwest Passage through Canada''s archipelago, and a future transpolar route — which could cut weeks off Asia-Europe voyages. Russia is developing the Northern Sea Route with nuclear icebreakers and the port of Sabetta, and China has folded it into a "Polar Silk Road". Coverage divides between an opportunity framing and a Western security framing that sees Russian control and Chinese encroachment as a strategic threat.','Der Wettbewerb um die Seewege, welche die arktische Erwärmung öffnet — die Nordostpassage entlang der russischen Küste, die Nordwestpassage durch den kanadischen Archipel und eine künftige transpolare Route — die Asien-Europa-Fahrten um Wochen verkürzen könnten. Russland entwickelt die Nordostpassage mit nuklearen Eisbrechern und dem Hafen Sabetta, und China hat sie in eine "polare Seidenstraße" eingebettet. Die Berichterstattung teilt sich zwischen einer Chancen-Rahmung und einer westlichen Sicherheits-Rahmung, welche die russische Kontrolle und chinesisches Vordringen als strategische Bedrohung sieht.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-NORDIC','AMERICAS-CANADA','ASIA-CHINA','NON-STATE-EU'],true,108,'Warming is opening sea routes that could reshape global trade — the Northern Sea Route along Russia''s coast, the Northwest Passage through Canada''s archipelago, and a future transpolar route — cutting weeks off Asia-Europe voyages. Russia is developing the Northern Sea Route with a nuclear-icebreaker fleet and the port of Sabetta, and China has folded the corridor into a "Polar Silk Road". Coverage divides between an opportunity framing from Russian, Chinese and commercial press that presents the routes as a shared economic prospect to be developed, and a strategic-threat framing from Western security press that sees Russian control of the passage, Chinese encroachment and a sanctions-evading "shadow fleet" as risks requiring monitoring and freedom-of-navigation assertion.','Die Erwärmung öffnet Seewege, die den globalen Handel umgestalten könnten — die Nordostpassage entlang der russischen Küste, die Nordwestpassage durch den kanadischen Archipel und eine künftige transpolare Route — und verkürzt Asien-Europa-Fahrten um Wochen. Russland entwickelt die Nordostpassage mit einer Flotte nuklearer Eisbrecher und dem Hafen Sabetta, und China hat den Korridor in eine "polare Seidenstraße" eingebettet. Die Berichterstattung teilt sich zwischen einer Chancen-Rahmung aus russischer, chinesischer und kommerzieller Presse, welche die Routen als gemeinsame wirtschaftliche Perspektive zur Entwicklung präsentiert, und einer Bedrohungs-Rahmung aus westlicher Sicherheitspresse, welche die russische Kontrolle der Passage, chinesisches Vordringen und eine sanktionsumgehende "Schattenflotte" als überwachungsbedürftige Risiken sieht.','atomic',NULL,'{}','regional',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_us_defence_dependence','Defence burden-sharing and US security guarantees','Verteidigungslastenteilung und US-Sicherheitsgarantien','The transactional dispute over who pays for and who guarantees European security. Washington presses its European allies to raise defence spending toward higher NATO targets, threatens and moves to draw down American troops in Europe, and casts doubt over the credibility of the US security guarantee and nuclear umbrella. Europeans are caught between paying more to keep Washington engaged and preparing for an America that may no longer come to their defence.','Der transaktionale Streit darüber, wer die europäische Sicherheit bezahlt und garantiert. Washington drängt seine europäischen Verbündeten, die Verteidigungsausgaben auf höhere NATO-Ziele anzuheben, droht mit dem Abzug amerikanischer Truppen aus Europa und zieht die Glaubwürdigkeit der US-Sicherheitsgarantie und des nuklearen Schirms in Zweifel. Die Europäer stehen zwischen der Notwendigkeit, mehr zu zahlen, um Washington eingebunden zu halten, und der Vorbereitung auf ein Amerika, das ihnen womöglich nicht mehr zu Hilfe kommt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC','NON-STATE-NATO'],true,31,'The transactional dispute at the heart of the alliance: who pays for and who guarantees European security. Washington presses its allies toward far higher NATO spending targets, threatens and begins to draw down American troops in Europe, and casts doubt over the credibility of the US security guarantee and nuclear umbrella. The result is an anxious Europe caught between paying more to keep America engaged and preparing for an ally that may no longer come to its defence. US conservative media frame it as overdue accountability for decades of European freeloading; Western and European mainstream media frame a fraying guarantee that leaves the continent dangerously exposed. (Its mirror image -- Europe''s own answer of rearmament and autonomy -- is tracked separately.)','Der transaktionale Streit im Kern des Bündnisses: wer die europäische Sicherheit bezahlt und wer sie garantiert. Washington drängt seine Verbündeten zu weit höheren NATO-Ausgabenzielen, droht mit dem Abzug amerikanischer Truppen aus Europa und beginnt damit, und zieht die Glaubwürdigkeit der US-Sicherheitsgarantie und des nuklearen Schirms in Zweifel. Das Ergebnis ist ein besorgtes Europa zwischen der Notwendigkeit, mehr zu zahlen, um Amerika eingebunden zu halten, und der Vorbereitung auf einen Verbündeten, der ihm womöglich nicht mehr zu Hilfe kommt. US-konservative Medien deuten dies als überfällige Rechenschaft für jahrzehntelanges europäisches Trittbrettfahren; westliche und europäische Mainstream-Medien als bröckelnde Garantie, die den Kontinent gefährlich entblößt.','atomic',NULL,'{}','regional',NULL,'AMERICAS-USA') ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_us_tech_sovereignty','Transatlantic tech regulation and digital sovereignty','Transatlantische Techregulierung und digitale Souveränität','The friction between European regulators and American technology power. The EU enforces the Digital Markets Act, Digital Services Act, GDPR and AI Act against US Big Tech through fines, antitrust probes and content rules; Washington pushes back in defence of its firms, threatening tariffs over "unfair" treatment; and Europe pursues digital sovereignty in parallel, weaning its cloud, software and defence data off American providers. It pits European rule-making and "sovereign cloud" ambitions against Silicon Valley''s dominance and US retaliation.','Die Reibung zwischen europäischen Regulierern und amerikanischer Technologiemacht. Die EU setzt den Digital Markets Act, den Digital Services Act, die DSGVO und den AI Act gegen die US-Techkonzerne durch — mit Bußgeldern, Kartellverfahren und Inhaltsregeln; Washington wehrt sich zur Verteidigung seiner Konzerne und droht mit Zöllen wegen „unfairer" Behandlung; und Europa verfolgt parallel die digitale Souveränität, indem es Cloud, Software und Verteidigungsdaten von amerikanischen Anbietern löst. Europäische Regelsetzung und „souveräne Cloud"-Ambitionen stehen gegen die Dominanz des Silicon Valley und US-Vergeltung.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC'],true,32,'The clash between European rule-making and American technological power. The EU wields the Digital Markets Act, Digital Services Act, GDPR and AI Act against US Big Tech through fines, antitrust probes and content and privacy rules; Washington pushes back in defence of its firms, threatening tariffs over what it calls discriminatory treatment; and Europe pursues digital sovereignty in parallel, trying to wean its cloud, software and even defence data off American providers. US conservative media frame the EU''s rules as protectionist harassment and censorship of American champions; European and Western mainstream media frame legitimate regulation and an overdue bid for digital sovereignty; and Russian and Chinese state media cast US tech dominance as a digital colonialism Europe is only now resisting.','Der Zusammenprall zwischen europäischer Regelsetzung und amerikanischer Technologiemacht. Die EU setzt den Digital Markets Act, den Digital Services Act, die DSGVO und den AI Act gegen die US-Techkonzerne ein -- mit Bußgeldern, Kartellverfahren sowie Inhalts- und Datenschutzregeln; Washington wehrt sich zur Verteidigung seiner Konzerne und droht mit Zöllen wegen angeblich diskriminierender Behandlung; und Europa verfolgt parallel die digitale Souveränität und versucht, Cloud, Software und selbst Verteidigungsdaten von amerikanischen Anbietern zu lösen. US-konservative Medien deuten die EU-Regeln als protektionistische Schikane und Zensur amerikanischer Konzerne; europäische und westliche Mainstream-Medien als legitime Regulierung und überfälliges Streben nach digitaler Souveränität; russische und chinesische Staatsmedien als digitalen Kolonialismus, dem sich Europa erst jetzt widersetzt.','atomic',NULL,'{}','regional',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eu_strategic_autonomy','European strategic autonomy and defence self-reliance','Europäische strategische Autonomie und verteidigungspolitische Eigenständigkeit','Europe''s drive to act as an independent strategic pole — to build the capacity to defend itself and decide for itself with less reliance on the United States. It spans the push for a European defence union, an "EU army" and a European nuclear deterrent, rearmament initiatives such as ReArm Europe and Readiness 2030, industrial sovereignty, and de-risking from dependence on both Washington and Beijing. The open question is whether Europe can and should emancipate itself, or whether strategic autonomy is an illusion without American power.','Europas Bestreben, als eigenständiger strategischer Pol zu handeln — die Fähigkeit aufzubauen, sich selbst zu verteidigen und selbst zu entscheiden, mit geringerer Abhängigkeit von den USA. Es umfasst den Vorstoß zu einer europäischen Verteidigungsunion, einer „EU-Armee" und einer europäischen nuklearen Abschreckung, Aufrüstungsinitiativen wie ReArm Europe und Readiness 2030, industrielle Souveränität und die Verringerung der Abhängigkeit von Washington wie von Peking. Offen ist, ob Europa sich emanzipieren kann und soll oder ob strategische Autonomie ohne amerikanische Macht eine Illusion bleibt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC','ASIA-CHINA'],true,30,'Europe''s answer to the US retreat: the drive to act as an independent strategic pole able to defend itself and decide for itself. It spans the push for a European defence union, an "EU army" and even a European nuclear deterrent, rearmament initiatives such as ReArm Europe and Readiness 2030, industrial sovereignty and de-risking from dependence on both Washington and Beijing. The open question -- can Europe, and will it dare? -- divides coverage: US conservative and Atlanticist-hawk media dismiss strategic autonomy as a costly fantasy that duplicates and weakens NATO; Western and European mainstream media frame a historic awakening the continent must see through; and Russian and Chinese state media welcome it as the fracturing of US hegemony and the arrival of a multipolar order.','Europas Antwort auf den US-Rückzug: das Streben, als eigenständiger strategischer Pol zu handeln, der sich selbst verteidigen und selbst entscheiden kann. Es umfasst den Vorstoß zu einer europäischen Verteidigungsunion, einer „EU-Armee" und sogar einer europäischen nuklearen Abschreckung, Aufrüstungsinitiativen wie ReArm Europe und Readiness 2030, industrielle Souveränität und die Verringerung der Abhängigkeit von Washington wie von Peking. Die offene Frage -- kann Europa, und wird es wagen? -- spaltet die Berichterstattung: US-konservative und atlantisch-restriktive Medien tun die strategische Autonomie als teure Fantasie ab, die die NATO dupliziere und schwäche; westliche und europäische Mainstream-Medien sehen ein historisches Erwachen; russische und chinesische Staatsmedien begrüßen sie als Zerfall der US-Hegemonie.','atomic',NULL,'{}','regional',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('greenland_control','Greenland strategic control and Arctic geopolitics','Strategische Kontrolle über Grönland und Arktis-Geopolitik','The confrontation over Greenland after Washington escalated a long-standing interest into an open push for control, backed by tariff threats against objecting European allies. The island''s Arctic bases, rare-earth minerals and opening sea lanes make it strategically pivotal, but the fight runs along a transatlantic axis — the United States against Denmark, the EU and NATO partners — with Greenlanders'' own claim to self-determination cutting across both. Framings range from a US strategic claim to a European defense of sovereignty to a pro-Kremlin reading that treats the episode as proof of Western imperialism and hypocrisy.','Die Konfrontation um Grönland, nachdem Washington ein langjähriges Interesse zu einem offenen Vorstoß zur Kontrolle eskaliert hat, untermauert durch Zolldrohungen gegen widersprechende europäische Verbündete. Die arktischen Stützpunkte der Insel, ihre Seltenen Erden und die sich öffnenden Seewege machen sie strategisch entscheidend, doch der Konflikt verläuft transatlantisch — die USA gegen Dänemark, die EU und NATO-Partner — mit dem grönländischen Anspruch auf Selbstbestimmung quer dazu. Die Deutungen reichen von einem strategischen US-Anspruch über eine europäische Verteidigung der Souveränität bis zu einer pro-Kreml-Lesart, die die Episode als Beweis westlicher Heuchelei und Imperialismus behandelt.',ARRAY['EUROPE-GREENLAND','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','NON-STATE-EU','NON-STATE-NATO','EUROPE-RUSSIA'],true,109,'Greenland has become the sharpest flashpoint of Arctic geopolitics after Washington escalated a long-standing interest into an open push for control, backed by tariff threats against European allies who object. The island''s value is triple — Arctic military basing at Pituffik, rare-earth minerals, and the sea lanes opening off its coast — but the confrontation runs along a transatlantic axis: the United States against Denmark, the EU and NATO partners, with Greenlanders'' own voice for self-determination cutting across both. Four readings compete: a US strategic, manifest-destiny claim that is thinly held; a European defense of Danish sovereignty and international law; a Greenlandic insistence that only Greenlanders decide; and a pro-Kremlin and Chinese framing that treats the episode not as support for a US takeover but as proof of Western imperialism and hypocrisy, amplifying the rift it opens.','Grönland ist zum schärfsten Brennpunkt der arktischen Geopolitik geworden, nachdem Washington ein langjähriges Interesse zu einem offenen Vorstoß zur Kontrolle eskaliert hat, untermauert durch Zolldrohungen gegen widersprechende europäische Verbündete. Der Wert der Insel ist dreifach — arktische Militärstützpunkte in Pituffik, Seltene Erden und die vor ihrer Küste entstehenden Seewege — doch die Konfrontation verläuft transatlantisch: die USA gegen Dänemark, die EU und NATO-Partner, mit der grönländischen Stimme für Selbstbestimmung quer dazu. Vier Lesarten konkurrieren: ein dünn vertretener strategischer US-Machtanspruch; eine europäische Verteidigung dänischer Souveränität und des Völkerrechts; ein grönländisches Beharren darauf, dass nur Grönländer entscheiden; und eine pro-Kreml- und chinesische Rahmung, die die Episode nicht als Zustimmung zu einer US-Übernahme deutet, sondern als Beweis westlicher Heuchelei und Imperialismus.','atomic',NULL,'{}','regional',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('transatlantic_trade','Transatlantic trade disputes and tariffs','Transatlantische Handelskonflikte und Zölle','The tariff and trade confrontation between the United States and the European Union under a protectionist Washington: US duties on European steel, aluminium, cars and other goods, the threatened and imposed counter-tariffs from Brussels, and the fragile framework trade deal negotiated to contain them. It extends to digital-services taxes, subsidy and market-access disputes and the Airbus-Boeing legacy, with European unity repeatedly tested over whether to retaliate against Washington or accommodate it.','Die Zoll- und Handelskonfrontation zwischen den USA und der Europäischen Union unter einem protektionistischen Washington: US-Abgaben auf europäischen Stahl, Aluminium, Autos und andere Waren, die angedrohten und verhängten Gegenzölle aus Brüssel und das fragile Rahmen-Handelsabkommen, das sie eindämmen soll. Sie reicht bis zu Digitalsteuern, Subventions- und Marktzugangsstreitigkeiten und dem Airbus-Boeing-Erbe, wobei die europäische Einigkeit immer wieder auf die Probe gestellt wird — Vergeltung gegen Washington oder Entgegenkommen.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC'],true,29,'The economic front of the transatlantic rift. A protectionist Washington has imposed and threatened tariffs on European steel, aluminium, cars and other goods, drawing threatened counter-tariffs from Brussels and repeated brinkmanship around a fragile framework deal meant to contain the damage. It reaches into digital-services taxes, subsidy fights and market access, and repeatedly tests whether the EU can hold a united line -- retaliating hard or accommodating -- as member states weigh exposed export industries against the cost of a trade war. US conservative outlets frame the tariffs as a justified correction of an unfair European surplus; European and Western mainstream coverage frames them as economic coercion demanding a firm, united response.','Die wirtschaftliche Front des transatlantischen Risses. Ein protektionistisches Washington hat Zölle auf europäischen Stahl, Aluminium, Autos und andere Waren verhängt und angedroht, angedrohte Gegenzölle aus Brüssel provoziert und wiederholt an den Rand der Eskalation um ein fragiles Rahmenabkommen geführt, das den Schaden begrenzen soll. Sie reicht bis zu Digitalsteuern, Subventionsstreitigkeiten und Marktzugang und prüft immer wieder, ob die EU eine geschlossene Linie halten kann -- harte Vergeltung oder Entgegenkommen. US-konservative Medien deuten die Zölle als berechtigte Korrektur eines unfairen europäischen Überschusses; europäische und westliche Mainstream-Berichterstattung als wirtschaftlichen Zwang, der eine feste, geschlossene Antwort verlangt.','atomic',NULL,'{}','regional',NULL,'AMERICAS-USA') ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('arctic_theater','Arctic strategic competition','Strategischer Wettbewerb in der Arktis','The contest over the Arctic as retreating sea ice opens once-inaccessible waters, seabed and sea lanes to competition among the eight Arctic states and China. Four axes run through it: the militarization of the High North and NATO''s northern expansion, the race for Arctic hydrocarbons and critical minerals, control of the emerging shipping routes, and the confrontation over Greenland that has strained transatlantic relations. Coverage is sharply divided — Western outlets frame Russian and Chinese activity as encroachment requiring deterrence, while Moscow and Beijing frame NATO''s build-up and the US Greenland push as the destabilizing provocation.','Der Wettstreit um die Arktis, während das zurückweichende Meereis einst unzugängliche Gewässer, Meeresböden und Seewege dem Wettbewerb zwischen den acht Arktis-Staaten und China öffnet. Vier Achsen durchziehen ihn: die Militarisierung des hohen Nordens und die Nordausdehnung der NATO, das Rennen um arktische Kohlenwasserstoffe und kritische Rohstoffe, die Kontrolle über die entstehenden Schifffahrtsrouten und die Konfrontation um Grönland, die die transatlantischen Beziehungen belastet hat. Die Berichterstattung ist tief gespalten — westliche Medien deuten russische und chinesische Aktivitäten als Vordringen, das Abschreckung erfordert, während Moskau und Peking den NATO-Aufbau und den US-Vorstoß in Grönland als destabilisierende Provokation darstellen.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA','EUROPE-NORDIC','AMERICAS-CANADA','ASIA-CHINA','NON-STATE-EU','EUROPE-GREENLAND'],true,28,'The Arctic is emerging as a distinct arena of great-power competition as retreating sea ice opens once-inaccessible waters, seabed and sea lanes. It draws in the eight Arctic states plus China as a self-declared "near-Arctic" power, along four axes: the militarization of the High North and NATO''s northern expansion; the race for Arctic hydrocarbons and critical minerals; control of the emerging shipping routes; and — dominating current coverage — the confrontation over Greenland, where a US push for control has ruptured transatlantic relations. Warming is both the enabler that opens access and a planetary alarm running beneath all four. Coverage is sharply contested: Western outlets frame Russian and Chinese activity as encroachment requiring deterrence, Moscow and Beijing frame NATO''s build-up as the destabilizing provocation, and the same US move on Greenland is read as strategic necessity, unacceptable coercion, or imperial hypocrisy depending on the outlet.','Die Arktis entwickelt sich zu einer eigenständigen Arena des Großmächte-Wettbewerbs, da das zurückweichende Meereis einst unzugängliche Gewässer, Meeresböden und Seewege öffnet. Sie zieht die acht Arktis-Staaten sowie China als selbsternannte "arktisnahe" Macht an — entlang vier Achsen: die Militarisierung des hohen Nordens und die Nordausdehnung der NATO; das Rennen um arktische Kohlenwasserstoffe und kritische Rohstoffe; die Kontrolle über die entstehenden Schifffahrtsrouten; und — die aktuelle Berichterstattung dominierend — die Konfrontation um Grönland, wo ein US-Vorstoß zur Kontrolle die transatlantischen Beziehungen zerrüttet hat. Die Erwärmung ist zugleich Wegbereiter des Zugangs und planetarer Alarm unter allen vier Achsen. Die Berichterstattung ist stark umkämpft: westliche Medien deuten russische und chinesische Aktivitäten als Vordringen, das Abschreckung erfordert, Moskau und Peking deuten den NATO-Aufbau als destabilisierende Provokation, und derselbe US-Vorstoß in Grönland gilt je nach Medium als strategische Notwendigkeit, inakzeptabler Zwang oder imperiale Heuchelei.','theater',ARRAY['arctic_shipping_routes','arctic_military_presence','arctic_resources_competition','greenland_control'],ARRAY['northern_sea_route','hammerfest_melkoya_lng','norwegian_shelf_gas'],'regional','{"type": "Point", "coordinates": [15.6, 78.2]}',NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('europe_us_theater','Europe-US strategic tensions','Strategische Spannungen zwischen Europa und den USA','The widening rift between the United States and its European allies under a Washington that treats Europe more as a competitor than a partner. It runs along four axes: a tariff and trade confrontation; a dispute over defence burden-sharing and the credibility of the US security guarantee; Europe''s answering drive for strategic autonomy and rearmament; and a clash over technology regulation and digital sovereignty. Beneath them runs a deeper question of whether the transatlantic alliance that defined the post-war order still holds — a fracture Moscow and Beijing cover with schadenfreude.','Der wachsende Riss zwischen den USA und ihren europäischen Verbündeten unter einem Washington, das Europa eher als Konkurrenten denn als Partner behandelt. Er verläuft entlang vier Achsen: einer Zoll- und Handelskonfrontation; eines Streits über die Verteidigungslastenteilung und die Glaubwürdigkeit der US-Sicherheitsgarantie; Europas Gegenbewegung hin zu strategischer Autonomie und Aufrüstung; und eines Konflikts über Technologieregulierung und digitale Souveränität. Darunter liegt die tiefere Frage, ob das transatlantische Bündnis, das die Nachkriegsordnung prägte, noch trägt — ein Bruch, den Moskau und Peking mit Schadenfreude begleiten.',ARRAY['NON-STATE-EU','AMERICAS-USA','ASIA-CHINA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','EUROPE-SOUTH','EUROPE-BENELUX','EUROPE-NORDIC','NON-STATE-NATO'],true,8,'The transatlantic alliance that anchored the post-war order is under its sharpest strain in generations, as a Washington that treats Europe more as a competitor than a partner presses on four fronts at once: a tariff and trade war, blunt demands over defence burden-sharing paired with doubt over the US security guarantee, a confrontation over technology regulation, and -- provoked by all three -- Europe''s own drive for strategic autonomy. The through-line is a continent forced to ask whether it can still rely on America, and what it must build if it cannot. Coverage splits three ways: US conservative media frame the pressure as overdue discipline of a freeloading, over-regulating Europe; Western and European mainstream outlets frame it as the rupture of a vital partnership that Europe must answer with unity, autonomy and digital sovereignty; and Russian and Chinese state media read every quarrel as proof of Western hypocrisy and the arrival of a multipolar world.','Das transatlantische Bündnis, das die Nachkriegsordnung verankerte, steht unter der schärfsten Belastung seit Generationen, da ein Washington, das Europa eher als Konkurrenten denn als Partner behandelt, an vier Fronten zugleich drängt: einem Zoll- und Handelskrieg, harschen Forderungen zur Verteidigungslastenteilung bei gleichzeitigem Zweifel an der US-Sicherheitsgarantie, einer Konfrontation über Technologieregulierung und -- durch all das ausgelöst -- Europas eigenem Streben nach strategischer Autonomie. Der rote Faden ist ein Kontinent, der sich fragen muss, ob er sich noch auf Amerika verlassen kann und was er aufbauen muss, falls nicht. Die Berichterstattung teilt sich dreifach: US-konservative Medien deuten den Druck als überfällige Disziplinierung eines trittbrettfahrenden, überregulierenden Europas; westliche und europäische Mainstream-Medien als Bruch einer lebenswichtigen Partnerschaft, dem Europa mit Einigkeit, Autonomie und digitaler Souveränität begegnen müsse; russische und chinesische Staatsmedien lesen jeden Streit als Beweis westlicher Heuchelei und Anbruch einer multipolaren Welt.','theater',ARRAY['transatlantic_trade','europe_us_defence_dependence','eu_strategic_autonomy','europe_us_tech_sovereignty'],ARRAY['lane_transatlantic','lane_us_europe_lng','lane_us_europe_energy'],'global',NULL,NULL) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, description_en=EXCLUDED.description_en, description_de=EXCLUDED.description_de, centroid_ids=EXCLUDED.centroid_ids, is_active=EXCLUDED.is_active, display_order=EXCLUDED.display_order, editorial_summary_en=EXCLUDED.editorial_summary_en, editorial_summary_de=EXCLUDED.editorial_summary_de, fn_type=EXCLUDED.fn_type, member_fn_ids=EXCLUDED.member_fn_ids, affected_asset_ids=EXCLUDED.affected_asset_ids, scope=EXCLUDED.scope, anchor_point=EXCLUDED.anchor_point, primary_target=EXCLUDED.primary_target, updated_at=NOW();
INSERT INTO taxonomy_v3 (id,item_raw,aliases,is_active,is_stop_word,centroid_id,taxonomy_function,linked_id) VALUES ('9cdd68ec-3039-4bd3-929c-d3dad8181769','arctic_military_presence fn_anchor','{"ar": ["\u0627\u0644\u0642\u0637\u0628 \u0627\u0644\u0634\u0645\u0627\u0644\u064a", "\u0627\u0644\u0645\u0646\u0637\u0642\u0629 \u0627\u0644\u0642\u0637\u0628\u064a\u0629"], "de": ["Arktis", "Arktik", "Hoher Norden", "Barentssee", "Spitzbergen", "Lappland", "Nordflotte"], "en": ["Arctic", "High North", "Barents", "Kola Peninsula", "Murmansk", "Severomorsk", "Novaya Zemlya", "Franz Josef Land", "Svalbard", "Spitsbergen", "Finnmark", "Kirkenes", "Troms\u00f8", "Bardufoss", "Rovaniemi", "Lapland", "Northern Fleet", "Arctic Sentry", "Cold Response", "Nordic Response", "Arctic Forge", "Joint Viking", "Pituffik"], "es": ["\u00c1rtico", "Flota del Norte"], "fr": ["Arctique", "Grand Nord", "flotte du Nord"], "hi": ["\u0906\u0930\u094d\u0915\u091f\u093f\u0915"], "it": ["Artico"], "ja": ["\u5317\u6975", "\u5317\u65b9\u8266\u968a"], "ru": ["\u0410\u0440\u043a\u0442\u0438\u043a", "\u0417\u0430\u043f\u043e\u043b\u044f\u0440\u044c", "\u041a\u0440\u0430\u0439\u043d\u0435\u0433\u043e \u0421\u0435\u0432\u0435\u0440\u0430", "\u0411\u0430\u0440\u0435\u043d\u0446\u0435\u0432", "\u041a\u043e\u043b\u044c\u0441\u043a", "\u041c\u0443\u0440\u043c\u0430\u043d\u0441\u043a", "\u0421\u0435\u0432\u0435\u0440\u043e\u043c\u043e\u0440\u0441\u043a", "\u041d\u043e\u0432\u0430\u044f \u0417\u0435\u043c\u043b\u044f", "\u0421\u0435\u0432\u0435\u0440\u043d\u044b\u0439 \u0444\u043b\u043e\u0442"], "zh": ["\u5317\u6781", "\u5317\u65b9\u8230\u961f"]}',true,false,NULL,'fn_anchor','arctic_military_presence');
