INSERT INTO taxonomy_v3 (id,item_raw,aliases,is_active,is_stop_word,centroid_id,taxonomy_function,linked_id) VALUES ('aac3b8fe-5f0d-4c77-bd99-5b44bf4a0a87','transatlantic_trade fn_anchor','{"ar": ["\u062a\u0639\u0631\u064a\u0641\u0629", "\u0631\u0633\u0648\u0645 \u062c\u0645\u0631\u0643\u064a\u0629", "\u062d\u0631\u0628 \u062a\u062c\u0627\u0631\u064a\u0629", "\u0627\u062a\u0641\u0627\u0642 \u062a\u062c\u0627\u0631\u064a", "\u0627\u0644\u0639\u062c\u0632 \u0627\u0644\u062a\u062c\u0627\u0631\u064a", "\u0627\u0644\u0635\u0644\u0628"], "de": ["Zoll", "Z\u00f6lle", "Strafzoll", "Strafz\u00f6lle", "Vergeltungszoll", "Gegenzoll", "Handelskrieg", "Einfuhrzoll", "Handelsabkommen", "Handelsstreit", "Handelsdefizit", "Gegenma\u00dfnahme", "Stahl", "Subvention", "Autoz\u00f6lle"], "en": ["tariff", "tariffs", "counter-tariff", "retaliatory tariff", "trade war", "import duty", "import duties", "customs dut", "trade deal", "trade talks", "trade dispute", "trade deficit", "trade surplus", "countermeasure", "anti-dumping", "WTO", "Section 232", "steel", "aluminium", "aluminum", "car tariffs", "auto tariffs", "subsidy", "subsidies"], "es": ["arancel", "aranceles", "guerra comercial", "acuerdo comercial", "d\u00e9ficit comercial", "acero", "subvenci\u00f3n"], "fr": ["droits de douane", "tarifs douaniers", "guerre commerciale", "surtaxe", "accord commercial", "d\u00e9ficit commercial", "acier", "subvention"], "hi": ["\u091f\u0948\u0930\u093f\u092b", "\u0935\u094d\u092f\u093e\u092a\u093e\u0930 \u092f\u0941\u0926\u094d\u0927", "\u0936\u0941\u0932\u094d\u0915", "\u0935\u094d\u092f\u093e\u092a\u093e\u0930 \u0938\u092e\u091d\u094c\u0924\u093e", "\u0935\u094d\u092f\u093e\u092a\u093e\u0930 \u0918\u093e\u091f\u093e", "\u0907\u0938\u094d\u092a\u093e\u0924"], "it": ["dazi", "dazio", "guerra commerciale", "accordo commerciale", "disavanzo commerciale", "acciaio", "sussidi"], "ja": ["\u95a2\u7a0e", "\u8cbf\u6613\u6226\u4e89", "\u8cbf\u6613\u5354\u5b9a", "\u8cbf\u6613\u8d64\u5b57", "\u9244\u92fc"], "ru": ["\u0442\u0430\u0440\u0438\u0444", "\u043f\u043e\u0448\u043b\u0438\u043d", "\u0442\u043e\u0440\u0433\u043e\u0432\u0430\u044f \u0432\u043e\u0439\u043d\u0430", "\u0442\u043e\u0440\u0433\u043e\u0432\u043e\u0435 \u0441\u043e\u0433\u043b\u0430\u0448\u0435\u043d\u0438\u0435", "\u0442\u043e\u0440\u0433\u043e\u0432\u044b\u0439 \u0434\u0435\u0444\u0438\u0446\u0438\u0442", "\u0430\u043d\u0442\u0438\u0434\u0435\u043c\u043f\u0438\u043d\u0433", "\u0441\u0442\u0430\u043b\u044c", "\u0441\u0443\u0431\u0441\u0438\u0434\u0438"], "zh": ["\u5173\u7a0e", "\u8d38\u6613\u6218", "\u8d38\u6613\u534f\u8bae", "\u8d38\u6613\u9006\u5dee", "\u53cd\u503e\u9500", "\u94a2\u94c1", "\u8865\u8d34"]}',true,false,NULL,'fn_anchor','transatlantic_trade');
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_nato_deterrence','NATO must reinforce the Arctic to deter a growing Russian (and Chinese) threat','Die NATO muss die Arktis verstärken, um eine wachsende russische (und chinesische) Bedrohung abzuschrecken','Deterrence framing (Western/NATO/Nordic mainstream) holds that Russian rearmament in the High North and growing Sino-Russian Arctic cooperation require NATO reinforcement -- exercises, bases, icebreakers and readiness -- to defend allied territory and close a capability gap. Vocabulary: deter, defend the north, Russian threat, build-up, readiness, Arctic Sentry, Cold Response.','Die Abschreckungs-Rahmung (westlicher/NATO/nordischer Mainstream) sieht die russische Aufrüstung im hohen Norden und die wachsende russisch-chinesische Arktis-Kooperation als Grund für eine NATO-Verstärkung -- Übungen, Stützpunkte, Eisbrecher und Einsatzbereitschaft.',ARRAY['NON-STATE-NATO','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','NON-STATE-EU'],ARRAY['deter','deterrence','defend the north','Russian threat','build-up','readiness','reinforce','vulnerability','capability gap','exercise','Arctic Sentry','Cold Response','high north','protect','Abschreckung','russische Bedrohung'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','Military Times','Defense News','ERR News','LRT English','Atlantic Council','Politico','Kyiv Post'],'arctic_military_presence',1,'NATO Arctic deterrence necessary','NATO-Abschreckung in der Arktis notwendig',1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_nato_militarization','NATO is militarising the Arctic and provoking a dangerous new confrontation','Die NATO militarisiert die Arktis und provoziert eine gefährliche neue Konfrontation','Militarisation framing (Russian + Chinese state press) reverses the causality: NATO expansion, exercises and basing are the destabilising provocation that turns a zone of low tension into an arena of bloc confrontation and an arms race, encircling Russia. Vocabulary: militarisation, provocation, encirclement, destabilise, arms race, bloc confrontation.','Die Militarisierungs-Rahmung (russische und chinesische Staatspresse) kehrt die Kausalität um: NATO-Erweiterung, Übungen und Stützpunkte seien die destabilisierende Provokation, die eine Zone geringer Spannung in eine Arena der Blockkonfrontation und ein Wettrüsten verwandelt.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['militariz','militarisation','provocation','encirclement','encircl','destabiliz','arms race','bloc confrontation','aggressive','escalat','Cold War','buildup','Militarisierung','Provokation','Einkreisung','Wettrüsten'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Global Times','CGTN','China Daily','Xinhua','Press TV'],'arctic_military_presence',2,'NATO militarising the Arctic','NATO militarisiert die Arktis', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_resource_development','Arctic energy and minerals are a legitimate sovereign development opportunity','Arktische Energie und Rohstoffe sind eine legitime souveräne Entwicklungschance','Development framing (Russian state + Western energy/business press) treats Arctic hydrocarbons and critical minerals as a legitimate, economically vital resource to be developed -- new discoveries, investment, production and jobs -- as retreating ice opens access. Vocabulary: discovery, reserves, investment, production, energy security, billion barrels.','Die Entwicklungs-Rahmung (russische Staats- und westliche Wirtschaftspresse) sieht arktische Kohlenwasserstoffe und kritische Rohstoffe als legitime, wirtschaftlich wichtige Ressource -- neue Funde, Investitionen, Förderung und Arbeitsplätze -- während das zurückweichende Eis den Zugang öffnet.',ARRAY['EUROPE-RUSSIA','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','ASIA-CHINA'],ARRAY['discovery','reserves','investment','production','energy security','billion barrels','boom','extract','output','field','jobs','develop'],true,ARRAY['Bloomberg','OilPrice','Wall Street Journal','Financial Times','TASS (EN)','RT','RIA Novosti','Globe and Mail','CNBC'],'arctic_resources_competition',1,'Sovereign resource development','Souveräne Rohstoffentwicklung',1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_drilling_environmental_alarm','Arctic warming and resource extraction are an environmental and climate emergency','Arktische Erwärmung und Rohstoffförderung sind ein Umwelt- und Klimanotstand','Environmental-and-climate framing (Western/green press plus climate-science reporting) treats the Arctic as a warning system and a victim: record-low sea ice, accelerating melt and thawing permafrost are a planetary climate signal, while opening the ice to drilling, mining and shipping compounds the damage through oil-spill risk, black carbon and biodiversity loss. It is the pro-development camp''s own critics -- the same outlets that report the resource boom also sound the alarm -- so publisher alone cannot separate the stances; framing keywords do. Vocabulary: record low, warming, melting, thawing permafrost, fragile ecosystem, black carbon, pristine, ban drilling, reckless, climate.','Die Umwelt- und Klima-Rahmung (westliche/grüne Presse und Klimawissenschafts-Berichterstattung) sieht die Arktis als Warnsystem und Opfer: Rekordtief beim Meereis, beschleunigte Schmelze und tauender Permafrost sind ein planetares Klimasignal, während das Öffnen des Eises für Bohrungen, Bergbau und Schifffahrt den Schaden durch Ölpest-Risiko, Ruß und Biodiversitätsverlust vergrößert.',ARRAY['NON-STATE-EU','EUROPE-NORDIC','AMERICAS-USA'],ARRAY['fragile','ecosystem','climate','environmental','pollution','black carbon','warming','melting','melt','thaw','permafrost','record low','sea ice','ice loss','pristine','biodiversity','ban drilling','reckless','oil spill','protect the Arctic','emissions','carbon','fragiles Ökosystem','Umwelt','Klimaschutz','Klima','Erwärmung','Ölpest','Meereis','Rekordtief','Permafrost'],true,ARRAY['The Guardian','BBC World','Deutsche Welle','Euronews','France 24 (EN)','New York Times','El País','Le Monde','The Independent','Reuters','Channel NewsAsia','Associated Press','NPR','Al Jazeera'],'arctic_resources_competition',2,'Warming & environmental emergency','Erwärmung & Umweltnotstand', -1,true) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_route_opportunity','Melting ice opens Arctic sea routes as a shared economic opportunity','Das schmelzende Eis öffnet arktische Seewege als gemeinsame wirtschaftliche Chance','Opportunity framing (Russian + Chinese + commercial press) presents the Northern Sea Route, Northwest Passage and Polar Silk Road as shorter, developable trade corridors and a legitimate economic prospect, with icebreaker fleets and Arctic ports as investment. Vocabulary: shorter route, trade route, transit, Northern Sea Route, Polar Silk Road, cargo, icebreaker fleet.','Die Chancen-Rahmung (russische, chinesische und kommerzielle Presse) präsentiert die Nordostpassage, die Nordwestpassage und die polare Seidenstraße als kürzere, entwickelbare Handelskorridore und legitime Wirtschaftsperspektive -- mit Eisbrecherflotten und arktischen Häfen als Investition.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','EUROPE-NORDIC'],ARRAY['shorter route','trade route','transit','opportunity','cargo','shipping boom','Polar Silk Road','develop','commercial','icebreaker fleet','Seidenstraße','Handelsroute'],true,ARRAY['TASS (EN)','RT','RIA Novosti','CGTN','Global Times','China Daily','Xinhua','Bloomberg','OilPrice'],'arctic_shipping_routes',1,'Arctic routes as economic opportunity','Arktische Routen als wirtschaftliche Chance',1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_route_strategic_threat','Russian and Chinese control of Arctic routes is a strategic threat','Die russische und chinesische Kontrolle arktischer Routen ist eine strategische Bedrohung','Strategic-threat framing (Western security press) treats Russian dominance of the Northern Sea Route and China''s Polar Silk Road ambitions as a chokepoint risk requiring monitoring, freedom-of-navigation assertion and sanctions -- including the "shadow fleet" and dual-use shipping. Vocabulary: control, chokepoint, dominance, Chinese encroachment, dual-use, shadow fleet, freedom of navigation.','Die Bedrohungs-Rahmung (westliche Sicherheitspresse) sieht die russische Dominanz über die Nordostpassage und Chinas Ambitionen der polaren Seidenstraße als Nadelöhr-Risiko, das Überwachung, die Durchsetzung der Navigationsfreiheit und Sanktionen erfordert -- einschließlich der "Schattenflotte".',ARRAY['NON-STATE-NATO','AMERICAS-USA','EUROPE-NORDIC','NON-STATE-EU'],ARRAY['control','chokepoint','dominance','Russian control','Chinese encroachment','dual-use','shadow fleet','monitor','contest','freedom of navigation','strategic threat','militariz','sanctions','Bedrohung','Schattenflotte'],true,ARRAY['Reuters','BBC World','Financial Times','Wall Street Journal','New York Times','Military Times','Defense News','France 24 (EN)','Deutsche Welle','Euronews','Atlantic Council'],'arctic_shipping_routes',2,'Russian/Chinese route control as threat','Russische/chinesische Routenkontrolle als Bedrohung', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_western_security_consensus','The Arctic must be secured against Russian militarization and Sino-Russian encroachment','Die Arktis muss gegen russische Militarisierung und russisch-chinesisches Vordringen gesichert werden','Western security-consensus framing (NATO, Nordic and US mainstream plus Western business press) holds that the Arctic is becoming a zone of strategic vulnerability that must be secured: Russian rearmament in the High North and deepening Sino-Russian cooperation require NATO deterrence, resource and shipping-route access must be protected, and allied sovereignty defended. Vocabulary: deter, Russian threat, encroachment, defend the north, freedom of navigation, security.','Die westliche Sicherheitskonsens-Rahmung (NATO, nordischer und US-Mainstream sowie westliche Wirtschaftspresse) sieht die Arktis als eine Zone strategischer Verwundbarkeit, die gesichert werden muss: russische Aufrüstung im hohen Norden und vertiefte russisch-chinesische Kooperation erfordern NATO-Abschreckung, der Zugang zu Rohstoffen und Schifffahrtsrouten muss geschützt und die Souveränität der Verbündeten verteidigt werden.',ARRAY['NON-STATE-NATO','EUROPE-NORDIC','AMERICAS-USA','AMERICAS-CANADA','NON-STATE-EU'],ARRAY['deter','deterrence','Russian threat','encroachment','defend','defend the north','security','build-up','freedom of navigation','reinforce','high north'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','New York Times','Washington Post','NPR','CNN','ABC News','Military Times','Defense News','ERR News','LRT English','Atlantic Council','Politico','Bloomberg','OilPrice','Globe and Mail','CNBC','Fox News'],'arctic_theater',1,'Western Arctic security consensus','Westlicher Sicherheitskonsens in der Arktis',2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_russia_china_counter','NATO expansion and the US Greenland grab are the real provocation and Western hypocrisy','NATO-Erweiterung und der US-Griff nach Grönland sind die eigentliche Provokation und westliche Heuchelei','Russian and Chinese counter-framing (Russian state press and Chinese state media) reverses the Western account: NATO''s northern expansion is the destabilizing militarization of a once-low-tension zone and an encirclement of Russia, and the US push on Greenland is imperialist overreach that exposes Western hypocrisy -- not a threat Moscow or Beijing pose but a pretext. It is adversarial to the Western Arctic posture as a whole. Vocabulary: militarization, provocation, encirclement, imperialism, hypocrisy, pretext.','Die russische und chinesische Gegen-Rahmung (russische Staatspresse und chinesische Staatsmedien) kehrt die westliche Darstellung um: Die Nordausdehnung der NATO sei die destabilisierende Militarisierung einer einst spannungsarmen Zone und eine Einkreisung Russlands, und der US-Vorstoß in Grönland sei imperialistische Überheblichkeit, die westliche Heuchelei entlarvt -- keine Bedrohung durch Moskau oder Peking, sondern ein Vorwand.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['militariz','provocation','encirclement','imperialism','imperialist','hypocrisy','pretext','land grab','destabiliz','bloc confrontation','double standard'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'arctic_theater',2,'Russian & Chinese counter-framing','Russische & chinesische Gegen-Rahmung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('arctic_western_sovereignty_stewardship','Coercion and reckless exploitation of the Arctic must be resisted — for allied sovereignty and the climate','Zwang und rücksichtslose Ausbeutung der Arktis müssen abgewehrt werden — für die Souveränität der Verbündeten und das Klima','Western sovereignty-and-stewardship framing (European and Western mainstream plus green press) resists the Arctic being carved up by coercion or reckless exploitation: it defends Danish and allied sovereignty and international law against the US Greenland push, is wary of Russian control of the sea routes, and treats the warming Arctic as a fragile climate system that drilling, mining and militarization endanger. Distinct from the security-consensus card, it is critical rather than martial. Vocabulary: sovereignty, coercion, international law, not for sale, warming, black carbon, fragile, climate.','Die westliche Souveränitäts- und Stewardship-Rahmung (europäischer und westlicher Mainstream sowie grüne Presse) wehrt sich gegen eine Aufteilung der Arktis durch Zwang oder rücksichtslose Ausbeutung: sie verteidigt die dänische und verbündete Souveränität und das Völkerrecht gegen den US-Vorstoß in Grönland, ist misstrauisch gegenüber russischer Kontrolle der Seewege und betrachtet die sich erwärmende Arktis als fragiles Klimasystem, das Bohrungen, Bergbau und Militarisierung gefährden.',ARRAY['NON-STATE-EU','EUROPE-NORDIC','EUROPE-GERMANY','EUROPE-FRANCE','AMERICAS-USA','AMERICAS-CANADA'],ARRAY['sovereignty','coercion','not for sale','international law','hands off','fragile','warming','black carbon','climate','environmental','self-determination','melting'],true,ARRAY['El País','Le Monde','The Independent','Channel NewsAsia','ANSA','EurActiv','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Al Jazeera','Anadolu Agency','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','BBC World','New York Times','Reuters','Associated Press'],'arctic_theater',3,'European sovereignty & environmental stewardship','Europäische Souveränität & Umweltverantwortung', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('defence_europe_must_pay','Europe has freeloaded on US protection for decades and must finally pay its share','Europa hat sich jahrzehntelang auf US-Schutz verlassen und muss endlich seinen Anteil zahlen','America-First framing (US conservative press) holds that European allies have underspent on defence for decades while sheltering under the US umbrella, and that Washington is right to demand they hit higher NATO spending targets or forfeit American protection. Troop drawdowns and blunt pressure are framed as overdue accountability. Vocabulary: freeload, fair share, pay up, 5 percent, deadbeat, burden, or else.','Die America-First-Rahmung (US-konservative Presse) sieht in den europäischen Verbündeten jahrzehntelange Trittbrettfahrer unter dem US-Schirm und hält es für richtig, dass Washington höhere NATO-Ausgabenziele fordert -- oder den amerikanischen Schutz entzieht. Truppenabzüge und harter Druck gelten als überfällige Rechenschaft.',ARRAY['AMERICAS-USA'],ARRAY['freeload','fair share','pay up','5 percent','deadbeat','burden','or else','delinquent','pull out','Trittbrettfahrer','fairer Anteil'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'europe_us_defence_dependence',1,'Europe must pay its share','Europa muss seinen Anteil zahlen',2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('defence_unreliable_america','A wavering America is an unreliable protector, forcing an alarmed Europe to scramble','Ein schwankendes Amerika ist ein unzuverlässiger Beschützer und zwingt ein alarmiertes Europa zum Handeln','Western mainstream framing treats the fraying US security guarantee -- troop drawdowns, doubts over Article 5, transactional pressure -- as a strategic shock that leaves Europe dangerously exposed. Allies scramble to reassure Washington and raise spending to keep it engaged, while asking whether America will still come to their defence. Vocabulary: unreliable, abandon, exposed, reassure, Article 5, credibility, nervous, scramble.','Der westliche Mainstream deutet die bröckelnde US-Sicherheitsgarantie -- Truppenabzüge, Zweifel an Artikel 5, transaktionalen Druck -- als strategischen Schock, der Europa gefährlich entblößt. Die Verbündeten bemühen sich, Washington zu beschwichtigen und die Ausgaben zu erhöhen, und fragen zugleich, ob Amerika noch zu ihrer Verteidigung käme.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['unreliable','abandon','exposed','reassure','Article 5','credibility','nervous','scramble','guarantee','umbrella','unzuverlässig','Abzug','Artikel 5'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','LRT English','ERR News','eKathimerini'],'europe_us_defence_dependence',2,'America the unreliable protector','Amerika als unzuverlässiger Beschützer', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('defence_nato_racket','NATO is a crumbling Cold-War racket through which the US bleeds Europe','Die NATO ist ein zerfallendes Relikt des Kalten Krieges, mit dem die USA Europa ausbluten','Rift-exploitation framing (Russian and Chinese state media) casts the burden-sharing rows as proof that NATO is an obsolete Cold-War racket: Washington extracts money and arms sales from dependent Europeans while the alliance''s internal quarrels reveal its decay. Adversarial to the alliance as a whole, amplified with schadenfreude, not support for either party. Vocabulary: racket, obsolete, Cold War relic, extort, arms sales, decay, disunity, crumbling.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) stellt die Lastenstreitigkeiten als Beweis dar, dass die NATO ein überholtes Relikt des Kalten Krieges sei: Washington presse Geld und Waffenkäufe aus abhängigen Europäern heraus, während die internen Querelen den Verfall des Bündnisses offenbarten.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['racket','obsolete','Cold War relic','extort','arms sales','decay','disunity','crumbling','vassal','proxy','Relikt','ausbluten','überholt'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'europe_us_defence_dependence',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tech_eu_overreach','EU tech rules are protectionist harassment of successful American companies','Die EU-Techregeln sind protektionistische Schikane erfolgreicher amerikanischer Unternehmen','America-First framing (US conservative press) casts the DMA, DSA and antitrust fines as protectionist, anti-innovation harassment designed to shake down US technology champions and censor American speech, justifying tariff retaliation to defend them. Vocabulary: shakedown, protectionist, harassment, censorship, anti-innovation, discriminatory, retaliate, defend our companies.','Die America-First-Rahmung (US-konservative Presse) deutet DMA, DSA und Kartellstrafen als protektionistische, innovationsfeindliche Schikane, die US-Techkonzerne abkassieren und amerikanische Meinungsäußerung zensieren solle -- und rechtfertigt Zoll-Vergeltung zu ihrer Verteidigung.',ARRAY['AMERICAS-USA'],ARRAY['shakedown','protectionist','harassment','censorship','anti-innovation','discriminatory','retaliate','defend our','targeting American','Schikane','Zensur','abkassieren'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'europe_us_tech_sovereignty',1,'EU regulatory overreach','EU-Regulierungsübergriff',2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tech_digital_sovereignty','Europe must rein in US Big Tech and reclaim its digital sovereignty','Europa muss die US-Techkonzerne bändigen und seine digitale Souveränität zurückgewinnen','Western and European mainstream framing treats EU enforcement against US Big Tech -- DMA/DSA fines, antitrust probes, content and privacy rules -- as legitimate rule-of-law that Europe must uphold, and pairs it with a drive for digital sovereignty: sovereign cloud, Gaia-X and weaning public and defence systems off American providers. Vocabulary: digital sovereignty, rein in, enforce, rule of law, sovereign cloud, dependence, gatekeeper, level playing field.','Der westliche und europäische Mainstream sieht in der EU-Durchsetzung gegen die US-Techkonzerne -- DMA/DSA-Strafen, Kartellverfahren, Inhalts- und Datenschutzregeln -- legitime Rechtsstaatlichkeit, die Europa wahren müsse, und verbindet sie mit dem Streben nach digitaler Souveränität: souveräne Cloud, Gaia-X und die Loslösung öffentlicher und militärischer Systeme von amerikanischen Anbietern.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['digital sovereignty','rein in','enforce','rule of law','sovereign cloud','dependence','gatekeeper','level playing field','regulate','Big Tech','digitale Souveränität','Kartell'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','Ars Technica','TechCrunch'],'europe_us_tech_sovereignty',2,'European digital sovereignty','Europäische digitale Souveränität', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('tech_digital_colonialism','US tech dominance is a digital colonialism Europe is only now waking up to','Die US-Techdominanz ist ein digitaler Kolonialismus, aus dem Europa erst jetzt erwacht','Rift-exploitation framing (Russian and Chinese state media) casts American technological dominance over Europe as digital colonialism and mass surveillance, presenting the EU-US tech clash as belated European recognition of its subjugation to Silicon Valley -- while stressing Washington''s hypocrisy on "free" markets. Adversarial to US tech hegemony, not an endorsement of EU regulation as such. Vocabulary: digital colonialism, surveillance, hegemony, subjugation, hypocrisy, control, dependence, monopoly.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) deutet die amerikanische Technologiedominanz über Europa als digitalen Kolonialismus und Massenüberwachung und stellt den EU-US-Techkonflikt als verspätetes europäisches Erkennen seiner Unterwerfung unter das Silicon Valley dar -- unter Betonung der Heuchelei Washingtons in Sachen „freier" Märkte.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['digital colonialism','surveillance','hegemony','subjugation','hypocrisy','control','dependence','monopoly','Silicon Valley','Kolonialismus','Überwachung','Hegemonie'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'europe_us_tech_sovereignty',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('europe_us_america_first','America First: a freeloading, over-regulating Europe must pay, open up and submit','America First: Ein trittbrettfahrendes, überregulierendes Europa muss zahlen, sich öffnen und fügen','America-First framing (US conservative press) runs across the whole theater: Europe has exploited US trade openness, freeloaded on US defence, and harasses American tech champions -- so tariffs, blunt burden-sharing pressure and retaliation over EU tech rules are justified tools to force fair terms and put America first. Europe is a partner to be disciplined, not indulged. Vocabulary: freeload, fair share, unfair, shakedown, America First, pay up, reciprocal.','Die America-First-Rahmung (US-konservative Presse) durchzieht das gesamte Theater: Europa habe die US-Handelsoffenheit ausgenutzt, sich beim US-Schutz als Trittbrettfahrer verhalten und schikaniere amerikanische Techkonzerne -- daher seien Zölle, harter Lastenteilungsdruck und Vergeltung gegen EU-Techregeln berechtigte Mittel, um faire Bedingungen zu erzwingen und Amerika an die erste Stelle zu setzen.',ARRAY['AMERICAS-USA'],ARRAY['steel','aluminium','car tariff','auto','automobile','digital tax','digital services tax','trade deal','framework','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','WTO','semiconductor','pharmaceutical','burden-sharing','burden sharing','defence spending','defense spending','troops','troop withdrawal','Ramstein','Article 5','nuclear umbrella','extended deterrence','DMA','Digital Markets Act','DSA','antitrust','Big Tech','GDPR','AI Act','digital sovereignty','cloud','gatekeeper','EU army','defence union','strategic autonomy','ReArm','rearmament','deterrent','de-risking','fair share','freeload','unfair','America First','rip off','reciprocal','pay up','delinquent','level playing field'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'europe_us_theater',1,'America First','America First',2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('europe_us_transatlantic_rupture','A vital alliance is rupturing, forcing an alarmed Europe to defend itself and its interests','Ein lebenswichtiges Bündnis zerbricht und zwingt ein alarmiertes Europa, sich und seine Interessen zu verteidigen','Western and European mainstream framing treats the Trump-era pressure -- tariffs, burden-sharing threats, wavering security guarantees, tech confrontation -- as the rupture of a decades-old partnership that leaves Europe exposed and coerced. The response it champions is unity, countermeasures, strategic autonomy and digital sovereignty: an alarmed continent forced to decide and defend for itself. Vocabulary: rupture, coercion, unreliable, autonomy, sovereignty, unity, defend, wake-up call.','Der westliche und europäische Mainstream deutet den Druck der Trump-Ära -- Zölle, Lastenteilungsdrohungen, schwankende Sicherheitsgarantien, Techkonfrontation -- als Bruch einer jahrzehntealten Partnerschaft, der Europa entblößt und unter Zwang setzt. Die befürwortete Antwort ist Einigkeit, Gegenmaßnahmen, strategische Autonomie und digitale Souveränität.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['steel','aluminium','car tariff','auto','automobile','digital tax','digital services tax','trade deal','framework','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','WTO','semiconductor','pharmaceutical','burden-sharing','burden sharing','defence spending','defense spending','troops','troop withdrawal','Ramstein','Article 5','nuclear umbrella','extended deterrence','DMA','Digital Markets Act','DSA','antitrust','Big Tech','GDPR','AI Act','digital sovereignty','cloud','gatekeeper','EU army','defence union','strategic autonomy','ReArm','rearmament','deterrent','de-risking','countermeasure','unity','autonomy','reassure','unreliable'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','LRT English','ERR News','eKathimerini','Ars Technica','TechCrunch'],'europe_us_theater',2,'Transatlantic rupture & European response','Transatlantischer Bruch & europäische Antwort', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('europe_us_western_disunity','The transatlantic split exposes Western hypocrisy and the arrival of a multipolar world','Der transatlantische Bruch entlarvt westliche Heuchelei und den Anbruch einer multipolaren Welt','Rift-exploitation framing (Russian and Chinese state media) reads every transatlantic quarrel -- tariffs, burden rows, the "EU army", tech fights -- not as taking sides but as proof that the US treats Europe as milkable vassals, that Western unity and values are hypocrisy, and that American hegemony is giving way to a multipolar order. Adversarial to the West as a bloc, amplified with schadenfreude. Vocabulary: vassal, hypocrisy, multipolar, end of hegemony, disunity, decline of the West, humiliation.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) liest jeden transatlantischen Streit -- Zölle, Lastenstreitigkeiten, „EU-Armee", Techkonflikte -- nicht als Parteinahme, sondern als Beweis, dass die USA Europa als auszunehmende Vasallen behandeln, westliche Einigkeit und Werte Heuchelei seien und die amerikanische Hegemonie einer multipolaren Ordnung weiche.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['steel','aluminium','car tariff','auto','automobile','digital tax','digital services tax','trade deal','framework','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','WTO','semiconductor','pharmaceutical','burden-sharing','burden sharing','defence spending','defense spending','troops','troop withdrawal','Ramstein','Article 5','nuclear umbrella','DMA','Digital Markets Act','DSA','antitrust','Big Tech','GDPR','AI Act','digital sovereignty','cloud','gatekeeper','EU army','defence union','strategic autonomy','ReArm','rearmament','deterrent','de-risking','vassal','hypocrisy','multipolar','humiliation','submission','end of hegemony'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'europe_us_theater',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('autonomy_illusion','European strategic autonomy is a costly fantasy that only weakens NATO','Europäische strategische Autonomie ist eine teure Fantasie, die nur die NATO schwächt','Skeptical framing (US conservative and Atlanticist-hawk press) mocks "strategic autonomy" and the "EU army" as a bureaucratic fantasy: Europe cannot defend itself, duplicates NATO, and should simply spend more inside the alliance rather than build rival structures that divide the West. Vocabulary: fantasy, pipe dream, duplication, cannot defend, paper army, undermine NATO, talk not troops.','Die skeptische Rahmung (US-konservative und atlantisch-restriktive Presse) verspottet „strategische Autonomie" und die „EU-Armee" als bürokratische Fantasie: Europa könne sich nicht selbst verteidigen, dupliziere die NATO und solle lieber innerhalb des Bündnisses mehr ausgeben, statt rivalisierende Strukturen aufzubauen, die den Westen spalten.',ARRAY['AMERICAS-USA'],ARRAY['fantasy','pipe dream','duplication','cannot defend','paper army','undermine NATO','illusion','talk not troops','Fantasie','Illusion','Papierarmee'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'eu_strategic_autonomy',1,'Autonomy is an illusion','Autonomie ist eine Illusion',2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('autonomy_european_awakening','Europe is finally awakening to strategic autonomy and must build its own defence','Europa erwacht endlich zur strategischen Autonomie und muss seine eigene Verteidigung aufbauen','Western mainstream framing treats the US retreat as the catalyst for a historic European awakening: the continent must build genuine strategic autonomy -- a defence union, industrial base, even a European deterrent -- through initiatives like ReArm Europe, to decide and defend for itself and de-risk from dependence on Washington. Broadly sympathetic to the project while debating its feasibility. Vocabulary: awakening, strategic autonomy, defence union, ReArm, sovereignty, self-reliance, wake-up call, emancipate.','Der westliche Mainstream deutet den US-Rückzug als Katalysator für ein historisches europäisches Erwachen: Der Kontinent müsse echte strategische Autonomie aufbauen -- eine Verteidigungsunion, eine industrielle Basis, sogar eine europäische Abschreckung -- über Initiativen wie ReArm Europe, um selbst zu entscheiden und sich zu verteidigen.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['awakening','strategic autonomy','defence union','ReArm','sovereignty','self-reliance','wake-up call','emancipate','rearm','deterrent','Erwachen','Autonomie','Verteidigungsunion'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','LRT English','ERR News','eKathimerini'],'eu_strategic_autonomy',2,'European strategic awakening','Europäisches strategisches Erwachen', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('autonomy_multipolar_welcome','European autonomy means the end of US hegemony and a welcome multipolar world','Europäische Autonomie bedeutet das Ende der US-Hegemonie und eine willkommene multipolare Welt','Rift-exploitation framing (Russian and Chinese state media) welcomes European "strategic autonomy" not out of solidarity but as the fracturing of the US-led bloc: proof that American hegemony is ending, that Europe should break free of its Atlantic vassalage, and that a multipolar order is arriving. It cheers the transatlantic split while doubting Europe will dare follow through. Vocabulary: multipolar, end of hegemony, vassalage, break free, Atlanticism dead, sovereignty, emancipation.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) begrüßt die europäische „strategische Autonomie" nicht aus Solidarität, sondern als Zerfall des US-geführten Blocks: als Beweis, dass die amerikanische Hegemonie ende, Europa sich aus atlantischer Vasallität lösen solle und eine multipolare Ordnung heraufziehe.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['multipolar','end of hegemony','vassalage','break free','Atlanticism','emancipation','sovereignty','declining America','Hegemonie','multipolar','Vasallität'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'eu_strategic_autonomy',3,'Multipolar rift-exploitation','Multipolare Riss-Ausnutzung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_us_strategic_claim','US control of Greenland is a strategic and national-security necessity','Die US-Kontrolle über Grönland ist eine strategische und sicherheitspolitische Notwendigkeit','US-manifest-destiny framing (Trump-aligned American press) holds that acquiring or controlling Greenland is a core national-security interest -- for Arctic bases, rare-earth minerals and sea lanes -- justified by Russian and Chinese encroachment, and that Washington should secure it "one way or the other". Genuine advocacy is thin relative to overall coverage. Vocabulary: core national security, strategic necessity, acquire Greenland, Arctic security, deal on the table.','Die Manifest-Destiny-Rahmung (Trump-nahe US-Presse) sieht die Übernahme oder Kontrolle Grönlands als zentrales nationales Sicherheitsinteresse -- für arktische Stützpunkte, Seltene Erden und Seewege -- gerechtfertigt durch russisches und chinesisches Vordringen.',ARRAY['AMERICAS-USA'],ARRAY['core national security','national security interest','strategic necessity','acquire Greenland','buy Greenland','get Greenland','take Greenland','one way or the other','won''t rule out','will not rule out','deal on the table','Arctic security','American Greenland','national sicherheit','Grönland kaufen','Grönland erwerben'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','The National Interest','Newsmax'],'greenland_control',1,'US strategic claim (manifest destiny)','US-Machtanspruch (Manifest Destiny)',2,true) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_sovereignty_defense','Coercion over Greenland is unacceptable; Danish/European sovereignty must be defended','Zwang gegen Grönland ist inakzeptabel; die dänische/europäische Souveränität muss verteidigt werden','Sovereignty-defense framing (Western mainstream) treats US pressure on Greenland as an unacceptable coercion of an ally, a violation of territorial integrity and international law, and a test of European unity -- met with condemnation, protests, counter-tariffs and troop deployments. It defends Denmark''s and the EU''s position against Washington. Vocabulary: hands off, not for sale, sovereignty, coercion, condemn, retaliate, allies, international law.','Die Souveränitäts-Rahmung (westlicher Mainstream) sieht den US-Druck auf Grönland als inakzeptablen Zwang gegen einen Verbündeten, als Verletzung der territorialen Integrität und des Völkerrechts und als Test der europäischen Einigkeit -- beantwortet mit Verurteilung, Protesten und Gegenzöllen.',ARRAY['NON-STATE-EU','EUROPE-NORDIC','EUROPE-GERMANY','EUROPE-FRANCE','AMERICAS-USA','AMERICAS-CANADA'],ARRAY['hands off','not for sale','sovereignty','territorial integrity','coercion','coerce','condemn','pushback','unacceptable','retaliate','counter-tariff','allies','international law','defend Greenland','rally','protest','red line','Souveränität','unverkäuflich','Hände weg','Völkerrecht','Vergeltung','Verbündete','inakzeptabel'],true,ARRAY['Reuters','BBC World','Financial Times','Associated Press','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','Wall Street Journal','Washington Post','New York Times','ABC News','NPR','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','CNN'],'greenland_control',2,'European/Danish sovereignty defense','Verteidigung europäischer/dänischer Souveränität', -1,true) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_self_determination','Greenland''s future is for Greenlanders to decide -- not Washington or Copenhagen','Über Grönlands Zukunft entscheiden die Grönländer -- nicht Washington oder Kopenhagen','Self-determination framing (Greenlandic/Nordic voices) centres Greenland''s own agency: the island is not for sale, its people decide their future, and the crisis accelerates the independence debate vis-à-vis both Denmark and the United States. Distinct from EU sovereignty-defense, which speaks for Denmark/Brussels. Vocabulary: self-determination, Greenlanders decide, our future, not for sale, independence, Inuit, referendum.','Die Selbstbestimmungs-Rahmung (grönländische/nordische Stimmen) stellt Grönlands eigene Handlungsmacht in den Mittelpunkt: die Insel ist nicht verkäuflich, ihr Volk entscheidet über seine Zukunft, und die Krise beschleunigt die Unabhängigkeitsdebatte gegenüber Dänemark und den USA.',ARRAY['EUROPE-GREENLAND','EUROPE-NORDIC'],ARRAY['self-determination','Greenlanders decide','our future','our country','right to decide','independence','Inuit','referendum','Naleraq','Egede','decide our','Selbstbestimmung','Unabhängigkeit','Grönländer'],true,ARRAY['Reuters','BBC World','Deutsche Welle','France 24 (EN)','Euronews','Associated Press','The Guardian','ERR News','LRT English','Anadolu Agency','Al Jazeera'],'greenland_control',3,'Greenlandic self-determination','Grönländische Selbstbestimmung',0,true) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('greenland_western_hypocrisy','US imperialism over Greenland exposes Western hypocrisy and disunity','Der US-Imperialismus um Grönland entlarvt westliche Heuchelei und Uneinigkeit','Rift-exploitation framing (Russian state press + Chinese state media) frames the episode not as support for a US takeover but as proof of Western hypocrisy and imperialism: Washington behaves as a 21st-century coloniser toward an ally, the "Russian/Chinese threat" to Greenland is a manufactured pretext (which even Western officials deny), and the transatlantic rift it opens is amplified with schadenfreude. It is adversarial to the US and to Western cohesion, NOT an endorsement of annexation. Vocabulary: imperialism, land grab, double standard, manufactured threat, northern outpost, ups ante, colonialism.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) deutet die Episode nicht als Zustimmung zu einer US-Übernahme, sondern als Beweis westlicher Heuchelei und Imperialismus: Washington verhält sich wie ein Kolonialherr des 21. Jahrhunderts, die "russisch-chinesische Bedrohung" Grönlands sei ein Vorwand, und der transatlantische Riss wird mit Schadenfreude verstärkt. Gegnerisch zu den USA und zur westlichen Geschlossenheit -- keine Zustimmung zur Annexion.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['imperialism','imperialist','land grab','takeover','double standard','hypocrisy','pretext','manufactured threat','inflating','so-called threat','colonial','colonialism','northern outpost','ups ante','21st century','coloniser'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'greenland_control',4,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_us_tariffs_justified','US tariffs are a justified correction of unfair European trade practices','US-Zölle sind eine berechtigte Korrektur unfairer europäischer Handelspraktiken','America-First framing (US conservative press) holds that decades of European trade surpluses, non-tariff barriers, VAT and digital taxes have exploited the United States, and that tariffs are a legitimate, overdue tool to force fair terms and reindustrialise America. Europe is cast as a freeloading partner that must open its market or pay. Vocabulary: unfair, surplus, level playing field, reciprocal, America First, fair deal.','Die America-First-Rahmung (US-konservative Presse) sieht in jahrzehntelangen europäischen Handelsüberschüssen, nichttarifären Barrieren, Mehrwert- und Digitalsteuern eine Ausbeutung der USA und in Zöllen ein legitimes, überfälliges Mittel, um faire Bedingungen zu erzwingen und Amerika zu reindustrialisieren.',ARRAY['AMERICAS-USA'],ARRAY['steel','aluminium','aluminum','car tariff','auto','automobile','vehicle','digital tax','digital services tax','trade deal','trade agreement','framework','wine','whisky','whiskey','bourbon','export','trade deficit','trade surplus','subsidy','subsidies','Airbus','Boeing','market access','WTO','Section 232','deadline','pharmaceutical','semiconductor','fair share','unfair','surplus','reciprocal','America First','rip off','level playing field','freeload','Stahl','Digitalsteuer','Autozölle','Handelsabkommen'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'transatlantic_trade',1,'US tariffs justified (America First)','US-Zölle gerechtfertigt (America First)',2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_european_defence','Trump''s tariffs are economic coercion that Europe must resist with unity and countermeasures','Trumps Zölle sind wirtschaftlicher Zwang, dem Europa mit Einigkeit und Gegenmaßnahmen begegnen muss','Western mainstream framing treats US tariffs as damaging economic coercion against a vital ally, threatening a mutually destructive trade war, and argues Europe must respond with unity, credible counter-tariffs and a negotiated deal that protects its industries and interests. Alarm at the rupture of a decades-old partnership runs throughout. Vocabulary: coercion, trade war, retaliate, counter-tariff, unity, escalation, negotiated deal, damage.','Der westliche Mainstream deutet die US-Zölle als schädlichen wirtschaftlichen Zwang gegen einen wichtigen Verbündeten, der einen zerstörerischen Handelskrieg droht, und fordert von Europa Einigkeit, glaubwürdige Gegenzölle und ein Verhandlungsergebnis, das seine Industrie und Interessen schützt.',ARRAY['NON-STATE-EU','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','AMERICAS-USA'],ARRAY['steel','aluminium','aluminum','car tariff','auto','automobile','vehicle','digital tax','digital services tax','trade deal','trade agreement','framework','wine','whisky','whiskey','bourbon','export','trade deficit','trade surplus','subsidy','subsidies','Airbus','Boeing','market access','WTO','Section 232','deadline','pharmaceutical','semiconductor','countermeasure','retaliate','counter-tariff','unity','negotiate','escalation','Stahl','Digitalsteuer','Autozölle','Handelsabkommen','Gegenzoll'],true,ARRAY['Reuters','Associated Press','BBC World','Financial Times','Wall Street Journal','New York Times','Washington Post','CNN','ABC News','NPR','The Guardian','Deutsche Welle','Euronews','France 24 (EN)','El País','Le Monde','ANSA','EurActiv','Politico','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Bloomberg','CNBC','Channel NewsAsia','The Independent','Helsinki Times','eKathimerini'],'transatlantic_trade',2,'European defence against US coercion','Europäische Abwehr gegen US-Zwang', -1,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_western_vassalage','US tariffs expose how Washington milks its European "vassals" and the hollowness of the alliance','US-Zölle zeigen, wie Washington seine europäischen „Vasallen" ausnimmt und wie hohl das Bündnis ist','Rift-exploitation framing (Russian and Chinese state media) presents the tariff war not by taking Europe''s or Washington''s side but as proof that the US treats its "allies" as vassals to be milked, that European submission is humiliating, and that the transatlantic economic bond is fracturing to the benefit of a multipolar world. Schadenfreude at Western disunity, not endorsement of either side. Vocabulary: vassal, milk, humiliation, submission, hypocrisy, extortion, multipolar, decline of the West.','Die Riss-Ausnutzungs-Rahmung (russische und chinesische Staatsmedien) ergreift weder für Europa noch für Washington Partei, sondern deutet den Zollkrieg als Beweis, dass die USA ihre „Verbündeten" wie auszunehmende Vasallen behandeln, die europäische Unterwerfung demütigend ist und das transatlantische Wirtschaftsband zugunsten einer multipolaren Welt zerbricht.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA'],ARRAY['steel','aluminium','aluminum','car tariff','auto','automobile','digital tax','digital services tax','trade deal','wine','whisky','export','trade deficit','subsidy','Airbus','Boeing','market access','WTO','semiconductor','pharmaceutical','vassal','milk','humiliation','submission','hypocrisy','extortion','multipolar'],true,ARRAY['RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Lenta.ru','Gazeta.ru','Izvestia','Kommersant','BelTA','Press TV','CGTN','Global Times','China Daily','Xinhua'],'transatlantic_trade',3,'Anti-Western rift-exploitation','Anti-westliche Riss-Ausnutzung', -2,false) ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_de=EXCLUDED.name_de, claim_en=EXCLUDED.claim_en, claim_de=EXCLUDED.claim_de, actor_centroids=EXCLUDED.actor_centroids, framing_keywords=EXCLUDED.framing_keywords, is_active=EXCLUDED.is_active, publishers=EXCLUDED.publishers, fn_id=EXCLUDED.fn_id, display_order=EXCLUDED.display_order, stance_label_en=EXCLUDED.stance_label_en, stance_label_de=EXCLUDED.stance_label_de, stance=EXCLUDED.stance, framing_required=EXCLUDED.framing_required, updated_at=NOW();
